INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (100, 'Episode 1: Kelahiran di Tengah Ancaman', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/id/kisah-nabi-musa-01-kelahiran.pdf', 1, 'original', 'Ditulis berdasarkan QS. Al-Qasas 3-13 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 1: Kelahiran di Tengah Ancaman', 'kisah-nabi-musa-01-kelahiran', 'id', 'kisah-nabi-musa', 1, 1, 'Kisah ini dibuka dengan sebuah negeri yang dicengkeram kezaliman. Fir''aun berlaku sewenang-wenang di bumi Mesir, memecah belah rakyatnya menjadi golongan-golongan, dan menindas salah satu golongan itu—menyembelih anak-anak lelaki mereka dan membiarkan hidup anak-anak perempuannya (QS. Al-Qasas: 4). Namun Allah berkehendak lain: hendak memberi karunia kepada mereka yang tertindas di bumi itu, menjadikan mereka pemimpin, dan mewariskan kepada mereka (QS. Al-Qasas: 5-6).

Di tengah kegelapan itulah Musa dilahirkan. Allah mengilhamkan kepada ibunya, "Susukanlah dia. Apabila engkau khawatir terhadapnya, letakkanlah dia di sungai, dan janganlah engkau khawatir dan jangan pula bersedih hati, karena sesungguhnya Kami akan mengembalikannya kepadamu dan menjadikannya salah seorang rasul" (QS. Al-Qasas: 7). Sebuah perintah yang tampak mustahil bagi akal, namun disertai janji yang pasti.

Keranjang kecil itu pun hanyut, dan dipungut oleh keluarga Fir''aun sendiri—kelak, sebagaimana difirmankan Allah, ia akan menjadi musuh dan kesedihan bagi mereka, meski mereka tidak menyadarinya (QS. Al-Qasas: 8). Istri Fir''aun, Asiyah, berkata, "Dia adalah penyejuk mata hati bagiku dan bagimu. Janganlah kamu membunuhnya; boleh jadi ia bermanfaat bagi kita" (QS. Al-Qasas: 9).

Hati ibu Musa dilanda kekosongan dan kecemasan yang nyaris membuatnya menyatakan siapa bayi itu sebenarnya, seandainya Allah tidak meneguhkan hatinya (QS. Al-Qasas: 10). Ia menyuruh kakak Musa mengikuti dari kejauhan. Karena Musa menolak setiap wanita yang hendak menyusuinya, sang kakak pun mengusulkan sebuah keluarga yang dapat mengasuhnya dengan tulus—dan tanpa mereka sadari, itulah keluarganya sendiri. Musa pun kembali ke pelukan ibunya, agar hatinya tenang, tidak bersedih, dan agar ia mengetahui bahwa janji Allah adalah benar (QS. Al-Qasas: 11-13).

Hikmah: rencana Allah kerap tersembunyi di balik peristiwa yang tampak menakutkan. Seorang ibu yang melepaskan anaknya ke sungai demi menaati wahyu mengajarkan bahwa tawakal sejati adalah menyerahkan hasil kepada Allah setelah menempuh sebab yang diperintahkan-Nya, betapa pun berat kelihatannya.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 28 AND number = 3), 100, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (101, 'Episode 1: Born Amid a Reign of Terror', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/en/kisah-nabi-musa-01-kelahiran.pdf', 1, 'original', 'Ditulis berdasarkan QS. Al-Qasas 3-13 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 1: Born Amid a Reign of Terror', 'kisah-nabi-musa-01-kelahiran', 'en', 'kisah-nabi-musa', 1, 1, 'The story opens in a land gripped by tyranny. Fir''aun (Pharaoh) had exalted himself in the land of Egypt, dividing its people into factions and oppressing one of them — slaughtering their sons while sparing their daughters (Qur''an 28:4). Yet Allah willed otherwise: to favor those oppressed in the land, to make them leaders, and to make them the inheritors (28:5-6).

Into this darkness, Musa (Moses) was born. Allah inspired his mother: "Nurse him, and when you fear for him, cast him into the river, and do not fear and do not grieve — indeed We will return him to you and make him a messenger" (28:7). A command that seemed impossible to reason, yet carried with it a certain promise.

The small basket drifted, and was retrieved by none other than Fir''aun''s own household — one day, as Allah later revealed, this child would become an enemy and a grief to them, though they did not yet know it (28:8). Fir''aun''s wife, Asiyah, said, "He will be a comfort of the eye for me and for you. Do not kill him; perhaps he may benefit us" (28:9).

The heart of Musa''s mother became empty with anxiety, and she nearly disclosed who he truly was, had Allah not strengthened her heart (28:10). She told his sister to follow him from a distance. Since Musa refused every wet-nurse offered to him, his sister suggested a family who could raise him with sincere care — unknowingly pointing them back to his own mother. Musa was thus returned to her arms, so that her eyes might be comforted, she would not grieve, and she would know that Allah''s promise is true (28:11-13).

Reflection: Allah''s plan is often hidden behind events that appear frightening. A mother releasing her child to a river in obedience to revelation teaches that true trust in Allah (tawakal) means surrendering the outcome to Him after taking the means He commands — however heavy that step may feel.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 28 AND number = 3), 101, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (102, 'Episode 2: Membela yang Tertindas, Melarikan Diri', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/id/kisah-nabi-musa-02-pelarian.pdf', 1, 'original', 'Ditulis berdasarkan QS. Al-Qasas 14-21 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 2: Membela yang Tertindas, Melarikan Diri', 'kisah-nabi-musa-02-pelarian', 'id', 'kisah-nabi-musa', 2, 1, 'Musa tumbuh dewasa. Ketika ia mencapai usia kematangan dan kesempurnaan, Allah menganugerahkan kepadanya hikmah dan ilmu—demikianlah Allah membalas orang-orang yang berbuat kebaikan (QS. Al-Qasas: 14).

Suatu hari, ia memasuki kota di saat penduduknya lengah, dan mendapati dua orang lelaki sedang berkelahi—satu dari kaumnya sendiri (Bani Israil), satu lagi dari pihak musuhnya (kaum Fir''aun). Orang dari kaumnya meminta pertolongan Musa melawan lawannya. Musa pun meninju orang itu hingga tewas. Menyadari beratnya perbuatannya, ia berkata, "Ini adalah perbuatan setan. Sesungguhnya setan itu musuh yang menyesatkan lagi nyata (permusuhannya)" (QS. Al-Qasas: 15).

Dengan hati yang gentar, Musa memohon, "Ya Tuhanku, sesungguhnya aku telah menzalimi diriku sendiri, maka ampunilah aku." Allah pun mengampuninya, karena Dialah Yang Maha Pengampun lagi Maha Penyayang (QS. Al-Qasas: 16). Musa lalu berjanji, "Ya Tuhanku, demi nikmat yang telah Engkau anugerahkan kepadaku, aku sekali-kali tiada akan menjadi penolong bagi orang-orang yang berdosa" (QS. Al-Qasas: 17).

Keesokan harinya, Musa berjalan di kota dengan perasaan takut sambil mengawasi keadaan. Orang yang kemarin meminta tolong kepadanya kembali berteriak meminta bantuan. Musa berkata kepadanya, "Sesungguhnya kamu benar-benar orang sesat yang nyata (kesesatannya)." Ketika Musa hendak menangkap orang yang menjadi musuh mereka berdua, orang itu—mengira Musa hendak menyerangnya—berkata, "Hai Musa, apakah kamu bermaksud hendak membunuhku sebagaimana kamu kemarin membunuh seseorang? Kamu tidak bermaksud melainkan hendak menjadi orang yang berbuat sewenang-wenang di negeri ini" (QS. Al-Qasas: 18-19).

Seorang laki-laki datang bergegas dari ujung kota, "Hai Musa, sesungguhnya pembesar negeri sedang berunding tentang kamu untuk membunuhmu. Maka keluarlah, sesungguhnya aku termasuk orang-orang yang memberi nasihat kepadamu" (QS. Al-Qasas: 20). Musa pun keluar dari kota itu dengan rasa takut menunggu-nunggu peristiwa, sambil berdoa, "Ya Tuhanku, selamatkanlah aku dari orang-orang yang zalim" (QS. Al-Qasas: 21).

Hikmah: Musa segera mengakui kesalahannya dan bertobat tanpa berlarut dalam pembelaan diri—sebuah teladan bahwa kebesaran seseorang bukan pada tidak pernah salah, melainkan pada kesediaannya untuk kembali kepada Allah sesegera mungkin.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 28 AND number = 14), 102, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (103, 'Episode 2: Defending the Oppressed, Fleeing for His Life', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/en/kisah-nabi-musa-02-pelarian.pdf', 1, 'original', 'Ditulis berdasarkan QS. Al-Qasas 14-21 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 2: Defending the Oppressed, Fleeing for His Life', 'kisah-nabi-musa-02-pelarian', 'en', 'kisah-nabi-musa', 2, 1, 'Musa grew into manhood. When he reached his full strength and maturity, Allah granted him wisdom and knowledge — thus does Allah reward those who do good (28:14).

One day, he entered the city at a time when its people were inattentive, and found two men fighting — one from his own people (the Children of Israel), the other from his enemy''s people (Fir''aun''s court). The man from his own people called on him for help against his opponent. Musa struck the man with his fist, and it killed him. Realizing the gravity of what he had done, he said, "This is from the work of Satan. Indeed, he is a manifest, misleading enemy" (28:15).

With a trembling heart, Musa pleaded, "My Lord, indeed I have wronged myself, so forgive me." And Allah forgave him — for He is the Forgiving, the Merciful (28:16). Musa then vowed, "My Lord, for the favor You bestowed upon me, I will never be a supporter of criminals" (28:17).

The next morning, Musa walked through the city fearful and watchful. The man who had asked for his help the day before cried out to him again. Musa said to him, "Indeed, you are clearly a man astray." When Musa moved to seize the man who was an enemy to them both, that man — thinking Musa meant to strike him — said, "O Musa, do you intend to kill me as you killed someone yesterday? You only want to be a tyrant in the land; you do not want to be one of the reformers" (28:18-19).

A man came running from the far end of the city: "O Musa, indeed the leaders are conspiring to kill you, so leave. I am indeed one of your sincere advisers" (28:20). Musa left the city, fearful, watching, praying, "My Lord, save me from the wrongdoing people" (28:21).

Reflection: Musa acknowledged his fault at once and turned to Allah without lingering in self-justification — a lesson that a person''s true greatness lies not in never erring, but in how swiftly they return to Allah when they do.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 28 AND number = 14), 103, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (104, 'Episode 3: Di Negeri Madyan', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/id/kisah-nabi-musa-03-madyan.pdf', 1, 'original', 'Ditulis berdasarkan QS. Al-Qasas 22-28 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 3: Di Negeri Madyan', 'kisah-nabi-musa-03-madyan', 'id', 'kisah-nabi-musa', 3, 1, 'Dalam pelariannya, Musa mengarahkan langkah menuju negeri Madyan seraya berdoa, "Mudah-mudahan Tuhanku memimpinku ke jalan yang benar" (QS. Al-Qasas: 22). Sesampainya di sumber air Madyan, ia mendapati sekumpulan orang sedang memberi minum ternak mereka, dan di belakang mereka dua orang perempuan yang menahan ternaknya. Musa bertanya, "Apakah maksudmu (dengan berbuat begitu)?" Keduanya menjawab, "Kami tidak dapat meminumkan (ternak kami), sebelum penggembala itu memulangkan (ternaknya); sedang bapak kami adalah orang tua yang telah lanjut umurnya" (QS. Al-Qasas: 23).

Musa pun membantu memberi minum ternak kedua perempuan itu, lalu berteduh sambil berdoa dengan penuh kerendahan hati, "Ya Tuhanku, sesungguhnya aku sangat memerlukan sesuatu kebaikan yang Engkau turunkan kepadaku" (QS. Al-Qasas: 24)—doa seorang musafir yang tidak memiliki apa pun kecuali harapan kepada Allah.

Salah seorang dari kedua perempuan itu datang menghampirinya dengan malu-malu, menyampaikan bahwa ayahnya mengundang Musa untuk memberinya upah atas jasanya. Ketika Musa menceritakan kisahnya, sang ayah berkata, "Janganlah kamu takut. Kamu telah selamat dari orang-orang yang zalim" (QS. Al-Qasas: 25). Salah seorang putrinya berkata, "Ya bapakku, ambillah ia sebagai orang yang bekerja (pada kita), karena sesungguhnya orang yang paling baik yang kamu ambil untuk bekerja (pada kita) ialah orang yang kuat lagi dapat dipercaya" (QS. Al-Qasas: 26).

Sang ayah pun menawarkan, "Sesungguhnya aku bermaksud menikahkan kamu dengan salah seorang dari kedua anakku ini, atas dasar bahwa kamu bekerja denganku delapan tahun; dan jika kamu cukupkan sepuluh tahun, maka itu adalah (suatu kebaikan) darimu" (QS. Al-Qasas: 27). Musa menerimanya dengan penuh kejujuran, "Itulah (perjanjian) antara aku dan kamu. Dan Allah adalah saksi atas apa yang kita ucapkan" (QS. Al-Qasas: 28).

Hikmah: pertolongan yang tulus—memberi minum ternak dua perempuan asing tanpa mengharap balasan—membuka jalan rezeki dan keluarga bagi Musa. Kebaikan kecil yang dilakukan dengan ikhlas kerap menjadi pintu bagi karunia yang jauh lebih besar dari yang dibayangkan.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 28 AND number = 22), 104, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (105, 'Episode 3: In the Land of Madyan', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/en/kisah-nabi-musa-03-madyan.pdf', 1, 'original', 'Ditulis berdasarkan QS. Al-Qasas 22-28 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 3: In the Land of Madyan', 'kisah-nabi-musa-03-madyan', 'en', 'kisah-nabi-musa', 3, 1, 'In his flight, Musa turned toward the land of Madyan, praying, "Perhaps my Lord will guide me to the right way" (28:22). When he reached its watering place, he found a crowd of people watering their flocks, and behind them two women holding their own flocks back. Musa asked, "What is the matter with you two?" They said, "We cannot water until the shepherds dispatch their flocks, and our father is an old man" (28:23).

So Musa watered their flocks for them, then withdrew to the shade and prayed with deep humility, "My Lord, indeed I am in need of whatever good You would send down to me" (28:24) — the prayer of a traveler who possessed nothing but hope in Allah.

One of the two women came to him walking shyly and told him her father was inviting him to reward him for his help. When Musa recounted his story, the old man said, "Do not fear. You have escaped the wrongdoing people" (28:25). One of the daughters said, "O my father, hire him — the best one you can hire is the one who is strong and trustworthy" (28:26).

The father then offered, "Indeed, I wish to marry you to one of these two daughters of mine, on condition that you serve me for eight years; and if you complete ten, that will be your own generosity" (28:27). Musa accepted with plain honesty, "That is between me and you. Whichever term I fulfill, let there be no injustice to me, and Allah is Witness over what we say" (28:28).

Reflection: a sincere act of help — watering the flocks of two women he did not know, expecting nothing in return — opened the door to provision and family for Musa. Small kindnesses done with sincerity often become the gateway to a favor far greater than one could have imagined.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 28 AND number = 22), 105, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (106, 'Episode 4: Api di Lembah Suci Thuwa', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/id/kisah-nabi-musa-04-lembah-thuwa.pdf', 1, 'original', 'Ditulis berdasarkan QS. Al-Qasas 29-35 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 4: Api di Lembah Suci Thuwa', 'kisah-nabi-musa-04-lembah-thuwa', 'id', 'kisah-nabi-musa', 4, 1, 'Setelah menuntaskan masa perjanjiannya, Musa melakukan perjalanan bersama keluarganya. Di tengah perjalanan itu, ia melihat api dari arah bukit Thur. Ia berkata kepada keluarganya, "Tunggulah (di sini), sesungguhnya aku melihat api. Mudah-mudahan aku dapat membawa suatu berita kepadamu daripadanya, atau (membawa) sesuluh api, agar kamu dapat menghangatkan badan" (QS. Al-Qasas: 29).

Ketika ia mendekati api itu, terdengarlah seruan dari sisi kanan lembah, dari sebatang pohon di tempat yang diberkahi, "Hai Musa, sesungguhnya Aku adalah Allah, Tuhan semesta alam" (QS. Al-Qasas: 30). Sebuah perjumpaan yang mengubah seluruh arah hidupnya—dari seorang pelarian menjadi penerima wahyu.

"Lemparkanlah tongkatmu," demikian perintah selanjutnya. Ketika Musa melihatnya bergerak-gerak seperti seekor ular, ia berbalik lari tanpa menoleh. "Hai Musa, datanglah kepada-Ku dan janganlah kamu takut. Sesungguhnya kamu termasuk orang-orang yang aman" (QS. Al-Qasas: 31). Kemudian, "Masukkanlah tanganmu ke leher bajumu, niscaya ia keluar putih tidak bercacat bukan karena penyakit, dan dekapkanlah kedua tanganmu (ke dada) bila ketakutan, maka yang demikian itu adalah dua mukjizat dari Tuhanmu (yang akan kamu hadapkan) kepada Fir''aun dan pembesar-pembesarnya. Sesungguhnya mereka adalah orang-orang yang fasik" (QS. Al-Qasas: 32).

Menyadari beratnya tugas yang diembankan, Musa berkata jujur tentang kekhawatirannya, "Ya Tuhanku, sesungguhnya aku telah membunuh seorang manusia dari golongan mereka, maka aku takut mereka akan membunuhku. Dan saudaraku Harun, dia lebih fasih lidahnya daripadaku, maka utuslah dia bersamaku sebagai pembantuku untuk membenarkan (perkataan)ku; sesungguhnya aku khawatir mereka akan mendustakanku" (QS. Al-Qasas: 33-34).

Allah menjawab dengan janji yang menenteramkan, "Kami akan membantumu dengan saudaramu, dan Kami berikan kepadamu berdua kekuasaan yang besar, maka mereka tidak dapat mencapaimu; (berangkatlah kamu berdua) dengan membawa mukjizat Kami, kamu berdua dan orang yang mengikuti kamulah yang akan menang" (QS. Al-Qasas: 35).

Hikmah: Musa tidak menyembunyikan rasa takut dan kekurangannya di hadapan Allah, melainkan menyampaikannya dengan jujur sambil tetap taat pada perintah. Kejujuran dalam berdoa, disertai kesungguhan menjalankan amanah, adalah bentuk keimanan yang matang.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 28 AND number = 29), 106, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (107, 'Episode 4: Fire at the Blessed Valley of Thuwa', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/en/kisah-nabi-musa-04-lembah-thuwa.pdf', 1, 'original', 'Ditulis berdasarkan QS. Al-Qasas 29-35 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 4: Fire at the Blessed Valley of Thuwa', 'kisah-nabi-musa-04-lembah-thuwa', 'en', 'kisah-nabi-musa', 4, 1, 'Having completed his term of service, Musa set off traveling with his family. Along the way, he noticed a fire in the direction of Mount Tur. He said to his family, "Stay here; I have seen a fire. Perhaps I will bring you news from it, or a burning torch so you may warm yourselves" (28:29).

As he approached the fire, a call rang out from the right side of the valley, from a tree in a blessed place: "O Musa, indeed I am Allah, Lord of the worlds" (28:30). An encounter that redirected the entire course of his life — from a fugitive into a recipient of revelation.

"Throw down your staff," came the next command. When Musa saw it moving as though it were a snake, he turned and fled without looking back. "O Musa, come forward and do not fear; indeed you are of those who are secure" (28:31). Then: "Insert your hand into the opening of your garment; it will come out white, without harm, and draw your arms in close to yourself when frightened. These are two proofs from your Lord to Fir''aun and his establishment; indeed they have been a defiantly disobedient people" (28:32).

Aware of the weight of the task now placed on him, Musa spoke honestly of his fear: "My Lord, indeed I killed a man among them, and I fear they will kill me. And my brother Harun is more fluent in speech than I am, so send him with me as support, to confirm my words; indeed I fear they will deny me" (28:33-34).

Allah answered with a reassuring promise: "We will strengthen your arm through your brother, and We will grant you both authority, so they will not reach you. With Our signs, you and those who follow you will be the predominant ones" (28:35).

Reflection: Musa did not conceal his fear or his limitations before Allah — he stated them honestly while still committing to obey. Honesty in prayer, paired with sincere resolve to carry out what one is entrusted with, is a mark of mature faith.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 28 AND number = 29), 107, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (108, 'Episode 5: Menghadap Fir''aun', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/id/kisah-nabi-musa-05-menghadap-firaun.pdf', 1, 'original', 'Ditulis berdasarkan QS. Asy-Syu''ara 10-51 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 5: Menghadap Fir''aun', 'kisah-nabi-musa-05-menghadap-firaun', 'id', 'kisah-nabi-musa', 5, 1, 'Allah memerintahkan, "Datangilah kaum yang zalim itu, (yaitu) kaum Fir''aun. Mengapa mereka tidak bertakwa?" (QS. Asy-Syu''ara: 10-11). Musa menjawab dengan jujur atas kekhawatirannya, "Ya Tuhanku, sesungguhnya aku takut bahwa mereka akan mendustakan aku. Dan (karenanya) sempit dadaku dan tidak lancar lidahku, maka utuslah (Jibril) kepada Harun (agar dia turut membantuku)" (QS. Asy-Syu''ara: 12-13). Allah menjawab, "Sekali-kali tidak (mereka tidak akan dapat membunuhmu), maka pergilah kamu berdua dengan membawa ayat-ayat Kami; sesungguhnya Kami bersamamu mendengarkan" (QS. Asy-Syu''ara: 15).

Di hadapan Fir''aun, Musa dan Harun menyampaikan, "Sesungguhnya kami adalah Rasul Tuhan semesta alam, lepaskanlah Bani Israil (pergi) bersama kami" (QS. Asy-Syu''ara: 16-17). Fir''aun mencoba merendahkan Musa dengan mengungkit masa kecilnya di istana dan pembunuhan yang pernah dilakukannya (QS. Asy-Syu''ara: 18-19). Musa mengakui kesalahannya dengan tenang, lalu menegaskan bahwa Allah telah mengaruniakan hikmah dan mengutusnya sebagai rasul (QS. Asy-Syu''ara: 20-21).

Ketika Fir''aun bertanya, "Siapa Tuhan semesta alam itu?", Musa menjawab dengan jawaban yang tegas dan agung, "Tuhan Pencipta langit dan bumi dan apa-apa yang di antara keduanya, jika kamu sungguh-sungguh orang yang meyakini" (QS. Asy-Syu''ara: 23-24). Fir''aun pun mengancam akan memenjarakan Musa, namun Musa tetap teguh menunjukkan bukti kenabiannya (QS. Asy-Syu''ara: 29-33): tongkatnya menjadi ular nyata, dan tangannya bersinar putih bagi yang memandang.

Para pembesar istana menuduh Musa sebagai penyihir ulung, sehingga Fir''aun mengumpulkan seluruh ahli sihir negerinya untuk sebuah pertarungan besar (QS. Asy-Syu''ara: 34-37). Ketika hari yang ditentukan tiba, para penyihir melemparkan tali dan tongkat mereka, menyihir mata orang banyak hingga tampak seperti ular-ular yang bergerak (QS. Asy-Syu''ara: 44). Namun ketika Musa melemparkan tongkatnya, ia menelan seluruh tipuan yang mereka buat (QS. Asy-Syu''ara: 45).

Para penyihir itu, yang semula direkrut untuk mengalahkan Musa, justru serentak tersungkur bersujud. "Kami beriman kepada Tuhan semesta alam, Tuhan Musa dan Harun" (QS. Asy-Syu''ara: 46-48)—sebuah keimanan yang lahir seketika di hadapan kebenaran, meski Fir''aun murka dan mengancam mereka dengan hukuman yang kejam (QS. Asy-Syu''ara: 49).

Hikmah: kebenaran yang nyata mampu menembus hati bahkan mereka yang semula direkrut untuk melawannya. Keteguhan Musa menghadapi ejekan dan ancaman mengajarkan bahwa dakwah yang disertai bukti dan kesabaran akan berbicara lebih keras daripada kekuasaan sebesar apa pun.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 26 AND number = 10), 108, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (109, 'Episode 5: Facing Fir''aun', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/en/kisah-nabi-musa-05-menghadap-firaun.pdf', 1, 'original', 'Ditulis berdasarkan QS. Asy-Syu''ara 10-51 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 5: Facing Fir''aun', 'kisah-nabi-musa-05-menghadap-firaun', 'en', 'kisah-nabi-musa', 5, 1, 'Allah commanded, "Go to the wrongdoing people, the people of Fir''aun. Will they not fear Allah?" (26:10-11). Musa answered honestly with his concern: "My Lord, indeed I fear they will deny me, and my breast will tighten and my tongue will not be fluent, so send for Harun" (26:12-13). Allah replied, "No — go both of you with Our signs; indeed We are with you, listening" (26:15).

Before Fir''aun, Musa and Harun declared, "Indeed, we are messengers of the Lord of the worlds — release the Children of Israel with us" (26:16-17). Fir''aun tried to belittle Musa by recalling his childhood in the palace and the killing he had once committed (26:18-19). Musa calmly acknowledged what had happened, then affirmed that Allah had granted him wisdom and sent him as a messenger (26:20-21).

When Fir''aun asked, "And what is the Lord of the worlds?", Musa answered with clarity and majesty: "Lord of the heavens and the earth and everything between them, if you would be certain" (26:23-24). Fir''aun threatened to imprison him, yet Musa steadfastly showed the proofs of his prophethood (26:29-33): his staff becoming a real serpent, his hand shining white for all to see.

The court accused Musa of being a master sorcerer, prompting Fir''aun to gather every skilled magician in the land for a great contest (26:34-37). When the appointed day came, the sorcerers cast down their ropes and staffs, bewitching the eyes of the onlookers so they appeared to slither like serpents (26:44). But when Musa cast down his own staff, it swallowed up everything they had fabricated (26:45).

The very sorcerers who had been recruited to defeat Musa fell down at once in prostration. "We have believed in the Lord of the worlds, the Lord of Musa and Harun," they declared (26:46-48) — a faith born instantly in the face of undeniable truth, even as Fir''aun raged and threatened them with brutal punishment (26:49).

Reflection: manifest truth can pierce even the hearts of those first recruited to oppose it. Musa''s steadfastness under mockery and threat teaches that a message carried with evidence and patience speaks louder than any earthly power.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 26 AND number = 10), 109, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (110, 'Episode 6: Keluar dari Mesir, Terbelahnya Laut', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/id/kisah-nabi-musa-06-terbelahnya-laut.pdf', 1, 'original', 'Ditulis berdasarkan QS. Asy-Syu''ara 52-68 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 6: Keluar dari Mesir, Terbelahnya Laut', 'kisah-nabi-musa-06-terbelahnya-laut', 'id', 'kisah-nabi-musa', 6, 1, 'Setelah bertahun-tahun penindasan, tibalah perintah keberangkatan. Allah mewahyukan kepada Musa, "Pergilah pada malam hari dengan membawa hamba-hamba-Ku (Bani Israil), sesungguhnya kamu sekalian akan disusuli" (QS. Asy-Syu''ara: 52). Fir''aun pun mengerahkan bala tentaranya ke seluruh negeri untuk mengumpulkan pasukan, dengan berkata, "Sesungguhnya mereka (Bani Israil) benar-benar golongan kecil, dan sesungguhnya mereka membuat hal-hal yang menimbulkan amarah kita, dan sesungguhnya kita adalah golongan yang selalu berjaga-jaga" (QS. Asy-Syu''ara: 53-56).

Maka Kami keluarkan Fir''aun dan kaumnya dari taman-taman dan mata air, dari perbendaharaan dan kedudukan yang mulia—demikianlah, dan Kami wariskan semua itu kepada Bani Israil (QS. Asy-Syu''ara: 57-59). Fir''aun dan bala tentaranya mengejar mereka pada waktu matahari terbit (QS. Asy-Syu''ara: 60).

Ketika kedua golongan itu saling melihat, para pengikut Musa berkata dengan gentar, "Sesungguhnya kita benar-benar akan tersusul." Musa menjawab dengan keyakinan yang tidak tergoyahkan, "Sekali-kali tidak akan tersusul; sesungguhnya Tuhanku besertaku, kelak Dia akan memberi petunjuk kepadaku" (QS. Asy-Syu''ara: 61-62)—kalimat yang menjadi salah satu ungkapan tawakal paling agung dalam sejarah para nabi, diucapkan tepat di tepi laut, dengan pasukan musuh di belakang dan air tak bertepi di hadapan.

Maka Kami wahyukan kepada Musa, "Pukullah lautan itu dengan tongkatmu." Maka terbelahlah lautan itu, dan tiap-tiap belahan adalah seperti gunung yang besar (QS. Asy-Syu''ara: 63). Kami dekatkan ke sana orang-orang yang lain (Fir''aun dan bala tentaranya mengikuti masuk ke jalan yang sama), dan Kami selamatkan Musa beserta orang-orang yang bersamanya semuanya, kemudian Kami tenggelamkan golongan yang lain itu (QS. Asy-Syu''ara: 64-66). Sebagaimana ditegaskan pula dalam surat lain, "Kami belah laut untuk kamu, lalu Kami selamatkan kamu dan Kami tenggelamkan (Fir''aun) sedang kamu sendiri menyaksikan" (QS. Al-Baqarah: 50).

Sesungguhnya pada yang demikian itu terdapat tanda (kekuasaan Allah), tetapi kebanyakan mereka tidak beriman. Dan sesungguhnya Tuhanmu, Dia-lah Yang Maha Perkasa lagi Maha Penyayang (QS. Asy-Syu''ara: 67-68).

Hikmah: keyakinan Musa di tepi laut—"Tuhanku besertaku"—adalah puncak dari seluruh perjalanan panjangnya sejak lahir dalam ancaman, dibesarkan dalam istana musuh, hingga menjadi rasul. Pertolongan Allah datang bukan sebelum keadaan tampak mustahil, melainkan justru pada titik paling genting, sebagai pengajaran bahwa tawakal sejati berdiri kokoh meski jalan keluar belum terlihat sama sekali.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 26 AND number = 52), 110, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (111, 'Episode 6: The Exodus, and the Sea Parts', 'Tim Editorial ULYAH', 'ebooks/kisah-nabi-musa/en/kisah-nabi-musa-06-terbelahnya-laut.pdf', 1, 'original', 'Ditulis berdasarkan QS. Asy-Syu''ara 52-68 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 6: The Exodus, and the Sea Parts', 'kisah-nabi-musa-06-terbelahnya-laut', 'en', 'kisah-nabi-musa', 6, 1, 'After years of oppression, the order to depart finally came. Allah revealed to Musa, "Travel by night with My servants (the Children of Israel); indeed, you will be pursued" (26:52). Fir''aun mobilized his forces throughout the land to muster an army, saying, "Indeed, these are but a small band, and indeed they are enraging us, and indeed we are a cautious, watchful people" (26:53-56).

So We removed Fir''aun and his people from gardens and springs, from treasures and a place of honor — thus it was, and We caused the Children of Israel to inherit all of it (26:57-59). Fir''aun and his army pursued them at sunrise (26:60).

When the two groups came within sight of each other, Musa''s companions cried out in fear, "Indeed, we are surely to be overtaken!" Musa answered with unshaken certainty, "No! Indeed, with me is my Lord; He will guide me" (26:61-62) — one of the most profound declarations of trust in Allah in the history of the prophets, spoken at the very edge of the sea, an army behind him and boundless water ahead.

Then We revealed to Musa, "Strike the sea with your staff." And it parted, each part like a great mountain (26:63). We brought the others near, and We saved Musa and all who were with him, then We drowned the rest (26:64-66). As affirmed elsewhere in the Qur''an: "We parted the sea for you, and We saved you and drowned the people of Fir''aun while you were looking on" (Qur''an 2:50).

Indeed in that is a sign, yet most of them do not believe. And indeed, your Lord — He is the Exalted in Might, the Merciful (26:67-68).

Reflection: Musa''s certainty at the water''s edge — "with me is my Lord" — was the culmination of his entire journey, from a birth under threat, to a childhood raised inside his enemy''s palace, to becoming a messenger. Allah''s help did not arrive before the situation looked impossible; it arrived at the most critical point of all, teaching that true trust in Allah stands firm even when no way out is yet visible.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 26 AND number = 52), 111, datetime('now');

